                        border:'1px solid rgba(239,68,68,0.3)',
                        color:'#ef4444',
                        borderRadius:'4px',
                        padding:'4px 8px',
                        fontSize:'12px',
                        cursor:'pointer',
                        transition:'all 0.15s'
                      }}
                      onMouseEnter={(e) => {
                        e.currentTarget.style.background='rgba(239,68,68,0.3)';
                      }}
                      onMouseLeave={(e) => {
                        e.currentTarget.style.background='rgba(239,68,68,0.2)';
                      }}
                    >
                      ✕
                    </button>
                  </div>
                ))}
              </div>

              {/* Add Entry Button */}
              <button
                type="button"
                onClick={addPauseEntry}
                style={{
                  background:'rgba(245,158,11,0.2)',
                  border:'1px solid rgba(245,158,11,0.3)',
                  color:'#f59e0b',
                  borderRadius:'6px',
                  padding:'6px 12px',
                  fontSize:'11px',
                  cursor:'pointer',
                  transition:'all 0.15s',
                  display:'flex',
                  alignItems:'center',
                  gap:'6px',
                  marginTop:'8px'
                }}
                onMouseEnter={(e) => {
                  e.currentTarget.style.background='rgba(245,158,11,0.3)';
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.background='rgba(245,158,11,0.2)';
                }}
              >
                ➕ Add Entry
              </button>
            </div>
          )}

          {/* Raise Request */}
          {form.task_type==='raise_request'&&(
            <>
              <div style={{marginBottom:10}}>
                <label className="form-label">Request Type</label>
                <select className="form-control" value={form.request_type} onChange={e=>f('request_type',e.target.value)}>
                  {REQUEST_TYPES.map(t=><option key={t} value={t}>{t.toUpperCase()}</option>)}
                </select>
              </div>
              <div style={{marginBottom:10}}>
                <label className="form-label">Details</label>
                <textarea className="form-control" style={{minHeight:60}} value={form.request_details} onChange={e=>f('request_details',e.target.value)} placeholder="Describe…"/>
              </div>
            </>
          )}

          {/* Optimise */}
          {form.task_type==='optimise'&&(
            <>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr 1fr',gap:8,marginBottom:10}}>
                <div><label className="form-label">FP</label><input className="form-control" placeholder="Enter FP" value={form.fp} onChange={e=>f('fp',e.target.value)}/></div>
                <div><label className="form-label">F1</label><input className="form-control" placeholder="Enter F1" value={form.f1} onChange={e=>f('f1',e.target.value)}/></div>
                <div><label className="form-label">F2</label><input className="form-control" placeholder="Enter F2" value={form.f2} onChange={e=>f('f2',e.target.value)}/></div>
              </div>
              <div style={{marginBottom:10}}>
                <label className="form-label">Scenario</label>
                <select className="form-control" value={form.optimise_scenario} onChange={e=>f('optimise_scenario',e.target.value)}>
                  <option value="">Select…</option>
                  {OPTIMISE_SCENARIOS.map(s=><option key={s} value={s}>{s}</option>)}
                </select>
              </div>
              <div style={{marginBottom:10}}>
                <label className="form-label">Attach File</label>
                <input ref={fileRef} type="file" style={{display:'none'}} onChange={e=>f('attachment',e.target.files[0])}/>
                <div style={{display:'flex',gap:8,alignItems:'center'}}>
                  <button type="button" className="btn btn-secondary btn-sm" onClick={()=>fileRef.current?.click()}>📎 Choose</button>
                  {form.attachment&&<span style={{fontSize:12,color:'var(--text-secondary)'}}>{form.attachment.name}</span>}
                </div>
              </div>
            </>
          )}

          <button className="btn btn-primary" style={{width:'100%',marginTop:4}} onClick={handleCreate} disabled={creating}>
            {creating?'Creating…':'✓ Create Task'}
          </button>
        </div>
      )}

      {/* task list */}
      <div style={{flex:1,overflowY:'auto',padding:'10px 12px'}}>
        {filtered.length===0?(
          <div className="empty-state" style={{padding:40}}><div style={{fontSize:32}}>✅</div><p>No {filter!=='all'?filter:''} tasks</p></div>
        ):filtered.map(task=>(
          <div id={`task-${task.id}`} key={task.id}>
            <TaskItem 
              key={task.id} 
              task={task} 
              currentUser={user} 
              onStatusUpdate={handleStatusUpdate} 
              onFollowup={handleFollowup}
              group={group} 
            />
          </div>
        ))}
      </div>
    </div>
  );
}
